package github.chains;

import com.github.javaparser.StaticJavaParser;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.body.MethodDeclaration;
import com.github.javaparser.ast.expr.MethodCallExpr;
import com.github.javaparser.ast.stmt.BlockStmt;
import com.github.javaparser.ast.stmt.CatchClause;
import com.github.javaparser.ast.stmt.TryStmt;
import com.github.javaparser.ast.type.ClassOrInterfaceType;

import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.ArrayList;
import java.util.List;
import java.util.stream.Collectors;

public class Main {
    public static void main(String[] args) throws IOException {
        if (args.length < 1) {
            System.err.println("Usage: java Main <source-directory>");
            System.exit(1);
        }

        String sourceDir = args[0];
        List<Path> javaFiles = findJavaFiles(Paths.get(sourceDir));

        for (Path file : javaFiles) {
            try {
                fixJacksonException(file);
                System.out.println("Processed: " + file);
            } catch (Exception e) {
                System.err.println("Error processing " + file + ": " + e.getMessage());
            }
        }
    }

    private static List<Path> findJavaFiles(Path directory) throws IOException {
        List<Path> javaFiles = new ArrayList<>();
        Files.walk(directory)
            .filter(p -> p.toString().endsWith(".java"))
            .forEach(javaFiles::add);
        return javaFiles;
    }

    private static void fixJacksonException(Path filePath) throws IOException {
        String content = Files.readString(filePath);

        if (!content.contains("ObjectWriter") || !content.contains("writeValue")) {
            return;
        }

        CompilationUnit cu = StaticJavaParser.parse(filePath);

        cu.findAll(MethodDeclaration.class).forEach(method -> {
            method.findAll(MethodCallExpr.class).forEach(methodCall -> {
                if (methodCall.getNameAsString().equals("writeValue")) {
                    if (methodCall.getScope().isPresent() && 
                        methodCall.getScope().get().toString().contains("ObjectWriter")) {
                        wrapInTryCatch(methodCall);
                    }
                }
            });
        });

        Files.writeString(filePath, cu.toString());
    }

    private static void wrapInTryCatch(MethodCallExpr methodCall) {
        if (methodCall.getParentNode().isEmpty()) {
            return;
        }

        if (!(methodCall.getParentNode().get() instanceof BlockStmt)) {
            return;
        }

        BlockStmt parentBlock = (BlockStmt) methodCall.getParentNode().get();

        TryStmt tryStmt = new TryStmt();
        BlockStmt tryBlock = new BlockStmt();

        List<com.github.javaparser.ast.stmt.Statement> statements = new ArrayList<>();
        boolean found = false;

        for (com.github.javaparser.ast.stmt.Statement stmt : parentBlock.getStatements()) {
            if (stmt.equals(methodCall) && !found) {
                tryBlock.addStatement(stmt);
                found = true;
            } else if (found) {
                statements.add(stmt);
            } else {
                statements.add(stmt);
            }
        }

        CatchClause catchClause = new CatchClause(
            new com.github.javaparser.ast.Parameter(
                new ClassOrInterfaceType(null, "IOException"),
                new com.github.javaparser.ast.Name("e")
            ),
            new BlockStmt()
        );
        catchClause.getBody().addStatement(
            new com.github.javaparser.ast.stmt.ThrowStmt(
                new com.github.javaparser.ast.expr.ObjectCreationExpr(
                    null,
                    new ClassOrInterfaceType(null, "IOException"),
                    com.github.javaparser.ast.NodeList.nodeListOf(
                        new com.github.javaparser.ast.expr.StringLiteralExpr("Error writing JSON: " + "${e.getMessage()}")
                    )
                )
            )
        );

        tryStmt.setTryBlock(tryBlock);
        tryStmt.addCatchClause(catchClause);

        parentBlock.clearStatements();
        for (com.github.javaparser.ast.stmt.Statement stmt : statements) {
            parentBlock.addStatement(stmt);
        }
        int insertIndex = 0;
        for (int i = 0; i < statements.size(); i++) {
            if (statements.get(i).toString().contains("ObjectWriter") || 
                statements.get(i).toString().contains("writer.")) {
                insertIndex = i + 1;
                break;
            }
        }
        parentBlock.addStatement(insertIndex, tryStmt);
    }
}

package github.chains;

import com.github.javaparser.StaticJavaParser;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.NodeList;
import com.github.javaparser.ast.expr.Expression;
import com.github.javaparser.ast.expr.ObjectCreationExpr;
import com.github.javaparser.ast.expr.StringLiteralExpr;
import com.github.javaparser.ast.nodeTypes.NodeWithElements;
import com.github.javaparser.ast.stmt.ExpressionStmt;
import com.github.javaparser.ast.stmt.Statement;
import com.github.javaparser.ast.visitor.VoidVisitorAdapter;

import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.ArrayList;
import java.util.List;

import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.NodeList;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.transform.Transformer;
import javax.xml.transform.TransformerFactory;
import javax.xml.transform.dom.DOMSource;
import javax.xml.transform.stream.StreamResult;

public class Main {
    public static void main(String[] args) throws Exception {
        if (args.length < 1) {
            System.err.println("Usage: java Main <pom-file-path>");
            System.exit(1);
        }

        String pomPath = args[0];
        fixJacksonVersion(pomPath);
        System.out.println("Fixed Jackson version mismatch in: " + pomPath);
    }

    public static void fixJacksonVersion(String pomPath) throws Exception {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        DocumentBuilder builder = factory.newDocumentBuilder();
        Document doc = builder.parse(new File(pomPath));

        NodeList dependencies = doc.getElementsByTagName("dependency");

        String jacksonDatabindVersion = null;
        Element jacksonCoreElement = null;

        for (int i = 0; i < dependencies.getLength(); i++) {
            Element dep = (Element) dependencies.item(i);
            String groupId = getCellValue(dep, "groupId");
            String artifactId = getCellValue(dep, "artifactId");

            if ("com.fasterxml.jackson.core".equals(groupId) && "jackson-databind".equals(artifactId)) {
                jacksonDatabindVersion = getCellValue(dep, "version");
            }

            if ("com.fasterxml.jackson.core".equals(groupId) && "jackson-core".equals(artifactId)) {
                jacksonCoreElement = dep;
            }
        }

        if (jacksonDatabindVersion != null && jacksonCoreElement != null) {
            Element versionElement = (Element) jacksonCoreElement.getElementsByTagName("version").item(0);
            if (versionElement != null) {
                versionElement.setTextContent(jacksonDatabindVersion);
            }
        }

        TransformerFactory transformerFactory = TransformerFactory.newInstance();
        Transformer transformer = transformerFactory.newTransformer();
        DOMSource source = new DOMSource(doc);
        StreamResult result = new StreamResult(new File(pomPath));
        transformer.transform(source, result);
    }

    private static String getCellValue(Element element, String tagName) {
        NodeList nodeList = element.getElementsByTagName(tagName);
        if (nodeList.getLength() > 0) {
            return nodeList.item(0).getTextContent();
        }
        return null;
    }
}

